image from PinterestSo instead of counting each valid substring one by one, I just counted how many layers were left from where I stood: s.length - right.
```
function numberOfSubstrings(s: string): number {
let left = 0;
let right = 0;
let count = 0;
let stack = [0, 0, 0];
for (let i = 0; i < s.length; i++){
if(s[i] === "a"){
stack [0]++
} else if(s[i] === "b"){
stack [1]++
} else {
stack [2]++
}
while (stack[0] > 0 && stack [1] > 0 && stack [2] > 0){
count += s.length - i
if(s[left] === "a"){
stack[0]--
} else if (s [left] === "b"){
stack [1]--
} else {
stack [2]--
}
left ++
}
}
return count
};
```
